{
  "task_id": "item-addon-order-001",
  "start_url": "https://dashdoor.rlgym.turing.com/home",
  "task_statement": "Log in using email 'lena.bennett71@example.com' and password 'c69fieW7G93U'. Order mac & cheese from West diner, select the extra cheese add on",
  "task_type": "GUI Comprehension, Action Execution",
  "simulator_config": {
    "start_date": "today",
    "user_persona": "lena.bennett71@example.com"
  },
  "grader_config": {
    "state_grader_configs": [
      {
        "assertions": [
          {
            "operator": "ARRAY_STRING_EQUALS",
            "path_to_actual": "$.restaurantId",
            "paths_to_expected": [
              "$[1].restaurants[0].id"
            ]
          },
          {
            "operator": "ARRAY_STRING_EQUALS",
            "path_to_actual": "$.items[0].name",
            "paths_to_expected": [
              "$[2].items[0].name"
            ]
          },
          {
            "expected": [
              "==1"
            ],
            "operator": "ARRAY_LENGTH_MATCH",
            "path_to_actual": "$.items[*]"
          },
          {
            "operator": "NUMERIC_MATCH",
            "path_to_actual": "$.items[0].quantity",
            "expected": [
              "==1"
            ]
          },
          {
            "operator": "STRING_EQUALS",
            "path_to_actual": "$.items[0].modifications[0].options[0].id",
            "paths_to_expected": [
              "$[3].modifications[0].options[0].id"
            ]
          }
        ],
        "path_to_actual": "$.orders[0]"
      }
    ],
    "extract_states_config": {
      "expected_state_functions": [
        {
          "args": {
            "user": "lena.bennett71@example.com"
          },
          "function": "get_user_address"
        },
        {
          "args": {
            "lat": "$[0].address.lat",
            "lng": "$[0].address.lng",
            "limit": 1,
            "name": "West diner"
          },
          "function": "get_restaurants"
        },
        {
          "args": {
            "limit": 1,
            "keywords": [
              "mac & cheese"
            ],
            "restaurant_id": "$[1].restaurants[0].id"
          },
          "function": "get_items"
        },
        {
          "args": {
            "item_id": "$[2].items[0].id",
            "modification_name": "add-ons",
            "option_name": "extra cheese"
          },
          "function": "get_modifications"
        }
      ]
    }
  }
}

{
  "task_id": "nearest-cheapest-choice-001",
  "start_url": "https://dashdoor.rlgym.turing.com/home",
  "task_statement": "Log in using email 'quinn.bennett2227@inbox.local' and password 'A6A4UaZcsiIp'. Order from the nearest vegetarian restaurant. Get either a grain bowl or a cucumber salad, choosing the cheaper option, and if they cost the same, pick the one with the higher rating. Have it delivered to my apartment address.",
  "task_type": "Multi-Step Task Planning, Action Execution, GUI Comprehension, Element Identification",
  "simulator_config": {
    "start_date": "today",
    "user_persona": "quinn.bennett2227@inbox.local"
  },
  "grader_config": {
    "state_grader_configs": [
      {
        "assertions": [
          {
            "operator": "STRING_EQUALS",
            "paths_to_expected": [
              "$.address.id"
            ]
          }
        ],
        "path_to_actual": "$.orders[0].deliveryAddress.id"
      },
      {
        "assertions": [
          {
            "operator": "STRING_EQUALS",
            "path_to_actual": "$.items[0].id",
            "paths_to_expected": [
              "$.items[0].id"
            ]
          },
          {
            "expected": [
              "==1"
            ],
            "operator": "ARRAY_LENGTH_MATCH",
            "path_to_actual": "$.items[*]"
          }
        ],
        "path_to_actual": "$.orders[0]"
      }
    ],
    "extract_states_config": {
      "expected_state_functions": [
        {
          "args": {
            "type": "apartment",
            "user": "quinn.bennett2227@inbox.local"
          },
          "function": "get_user_address"
        },
        {
          "args": {
            "lat": "$[0].address.lat",
            "lng": "$[0].address.lng",
            "limit": 1,
            "filters": {
              "cuisines": ["vegetarian"]
            },
            "sort_type": [
              {
                "key": "distance",
                "order": "asc"
              }
            ]
          },
          "function": "get_restaurants"
        },
        {
          "args": {
            "limit": 1,
            "keywords": [
              "cucumber salad",
              "grain bowl"
            ],
            "sort_type": [
              {
                "key": "price",
                "order": "asc"
              },
              {
                "key": "rating",
                "order": "desc"
              }
            ],
            "restaurant_id": "$[1].restaurants[0].id"
          },
          "function": "get_items"
        }
      ]
    }
  }
}

